@layer mergora.components {
  .mrg-heatmap {
    display: grid;
    gap: var(--mrg-semantic-space-stack-md);
    max-inline-size: 100%;
    padding: var(--mrg-semantic-density-panel-padding);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }
  .mrg-heatmap__legend {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--mrg-semantic-space-inline-xs);
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
  }
  .mrg-heatmap__legend [data-level] {
    display: grid;
    place-items: center;
    inline-size: var(--mrg-semantic-size-icon-sm);
    block-size: var(--mrg-semantic-size-icon-sm);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-foreground-primary);
  }
  .mrg-heatmap__grid {
    display: grid;
    gap: var(--mrg-semantic-space-inline-xs);
    overflow-x: auto;
  }
  .mrg-heatmap__row {
    display: grid;
    grid-template-columns: repeat(7, minmax(var(--mrg-semantic-size-target-minimum), 1fr));
    gap: var(--mrg-semantic-space-inline-xs);
  }
  .mrg-heatmap__grid button {
    min-inline-size: var(--mrg-semantic-size-target-minimum);
    min-block-size: var(--mrg-semantic-size-target-minimum);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: var(--mrg-semantic-font-weight-strong) var(--mrg-semantic-font-size-label) / 1
      var(--mrg-semantic-font-family-prose);
  }
  .mrg-heatmap [data-level="1"] {
    background: var(--mrg-semantic-color-status-success-background);
  }
  .mrg-heatmap [data-level="2"] {
    border-color: var(--mrg-semantic-color-status-success-border);
    background: var(--mrg-semantic-color-status-success-background);
  }
  .mrg-heatmap [data-level="3"] {
    border-color: var(--mrg-semantic-color-brand-action);
    color: var(--mrg-semantic-color-brand-action);
    background: var(--mrg-semantic-color-selection-background);
  }
  .mrg-heatmap [data-level="4"] {
    border-color: var(--mrg-semantic-color-brand-action);
    color: var(--mrg-semantic-color-action-foreground);
    background: var(--mrg-semantic-color-brand-action);
  }
  .mrg-heatmap__grid button[aria-selected="true"] {
    box-shadow: inset 0 0 0 var(--mrg-semantic-border-width-strong)
      var(--mrg-semantic-color-brand-violet);
  }
  .mrg-heatmap :is(button, summary):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }
  .mrg-heatmap__fallback {
    overflow: auto;
  }
  .mrg-heatmap__fallback summary {
    min-block-size: var(--mrg-semantic-size-target-minimum);
    font-weight: var(--mrg-semantic-font-weight-label);
    cursor: pointer;
  }
  .mrg-heatmap table {
    inline-size: 100%;
    border-collapse: collapse;
  }
  .mrg-heatmap th,
  .mrg-heatmap td {
    padding: var(--mrg-semantic-space-inset-sm);
    border-block-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    text-align: start;
  }
  .mrg-heatmap__summary {
    display: block;
    padding: var(--mrg-semantic-space-inset-xs) var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-status-info-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-status-info-foreground);
    background: var(--mrg-semantic-color-status-info-background);
    font-size: var(--mrg-semantic-font-size-label);
  }
  @media (pointer: coarse) {
    .mrg-heatmap__row {
      grid-template-columns: repeat(7, minmax(var(--mrg-semantic-size-target-preferred), 1fr));
    }
    .mrg-heatmap__grid button,
    .mrg-heatmap__fallback summary {
      min-inline-size: var(--mrg-semantic-size-target-preferred);
      min-block-size: var(--mrg-semantic-size-target-preferred);
    }
  }
  @media (forced-colors: active) {
    .mrg-heatmap,
    .mrg-heatmap__grid button,
    .mrg-heatmap__legend [data-level],
    .mrg-heatmap__summary {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-heatmap__grid button[aria-selected="true"] {
      box-shadow: inset 0 0 0 var(--mrg-semantic-border-width-strong) Highlight;
    }
    .mrg-heatmap :is(button, summary):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

"use client";

import "./calendar-heatmap.css";

import {
  useRef,
  useState,
  type HTMLAttributes,
  type KeyboardEvent,
  type ReactElement,
} from "react";

export interface CalendarHeatmapEntry {
  /** Supplies the canonical UTC calendar date in YYYY-MM-DD form. */
  readonly date: string;
  /** Supplies the finite intensity value used to derive the visual level. */
  readonly value: number;
  /** Overrides the generated accessible date-and-value label. */
  readonly label?: string;
}
export interface CalendarHeatmapProps extends Omit<
  HTMLAttributes<HTMLElement>,
  "children" | "onChange"
> {
  /** Supplies chronologically ordered date values for the grid and table fallback. */
  readonly entries: readonly CalendarHeatmapEntry[];
  /** Names the heatmap section, grid, and native table fallback. */
  readonly label: string;
  /** Overrides the runtime locale used for visible date formatting. */
  readonly locale?: string;
  /** Controls the selected calendar date when supplied. */
  readonly selectedDate?: string | null;
  /** Sets the initial selected date for uncontrolled use. */
  readonly defaultSelectedDate?: string | null;
  /** Reports pointer and keyboard date selection. */
  readonly onSelectedDateChange?: (date: string) => void;
  /** Shows a total-value live summary; false removes its output and computation. */
  readonly showSummary?: boolean;
}

function classes(...values: readonly (string | undefined | false)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}
function validDate(value: string): Date {
  const date = new Date(`${value}T00:00:00Z`);
  if (Number.isNaN(date.valueOf()))
    throw new RangeError("Mergora CalendarHeatmap dates must use a valid YYYY-MM-DD value.");
  return date;
}

export function CalendarHeatmap({
  entries,
  label,
  locale,
  selectedDate,
  defaultSelectedDate = null,
  onSelectedDateChange,
  showSummary = false,
  className,
  ...props
}: CalendarHeatmapProps): ReactElement {
  const [internalSelected, setInternalSelected] = useState<string | null>(defaultSelectedDate);
  const current = selectedDate === undefined ? internalSelected : selectedDate;
  const refs = useRef(new Map<string, HTMLButtonElement>());
  const maximum = Math.max(1, ...entries.map((entry) => entry.value));
  const formatter = new Intl.DateTimeFormat(locale, { dateStyle: "medium", timeZone: "UTC" });
  const select = (entry: CalendarHeatmapEntry) => {
    if (selectedDate === undefined) setInternalSelected(entry.date);
    onSelectedDateChange?.(entry.date);
  };
  const keyboard = (event: KeyboardEvent<HTMLButtonElement>, index: number) => {
    let next = index;
    if (event.key === "ArrowRight") next += props.dir === "rtl" ? -1 : 1;
    else if (event.key === "ArrowLeft") next += props.dir === "rtl" ? 1 : -1;
    else if (event.key === "ArrowDown") next += 7;
    else if (event.key === "ArrowUp") next -= 7;
    else if (event.key === "Home") next = 0;
    else if (event.key === "End") next = entries.length - 1;
    else return;
    event.preventDefault();
    const entry = entries[Math.min(entries.length - 1, Math.max(0, next))];
    if (entry !== undefined) {
      select(entry);
      refs.current.get(entry.date)?.focus();
    }
  };
  const total = showSummary ? entries.reduce((sum, entry) => sum + entry.value, 0) : 0;
  const calendarRows = Array.from({ length: Math.ceil(entries.length / 7) }, (_, rowIndex) =>
    entries.slice(rowIndex * 7, rowIndex * 7 + 7),
  );
  return (
    <section
      {...props}
      aria-label={label}
      className={classes("mrg-heatmap", className)}
      data-slot="calendar-heatmap"
    >
      <div className="mrg-heatmap__legend" aria-label="Intensity legend">
        <span>Less</span>
        {[0, 1, 2, 3, 4].map((level) => (
          <span key={level} aria-label={`Level ${level}`} data-level={level}>
            {level}
          </span>
        ))}
        <span>More</span>
      </div>
      <div role="grid" aria-label={`${label} values`} className="mrg-heatmap__grid">
        {calendarRows.map((row, rowIndex) => (
          <div key={row[0]?.date ?? `empty-${rowIndex}`} role="row" className="mrg-heatmap__row">
            {row.map((entry, columnIndex) => {
              const index = rowIndex * 7 + columnIndex;
              const level =
                entry.value === 0 ? 0 : Math.max(1, Math.ceil((entry.value / maximum) * 4));
              const dateLabel = formatter.format(validDate(entry.date));
              return (
                <button
                  key={entry.date}
                  ref={(node) => {
                    if (node === null) refs.current.delete(entry.date);
                    else refs.current.set(entry.date, node);
                  }}
                  type="button"
                  role="gridcell"
                  aria-label={entry.label ?? `${dateLabel}: ${entry.value}`}
                  aria-selected={current === entry.date}
                  tabIndex={current === entry.date || (current === null && index === 0) ? 0 : -1}
                  data-level={level}
                  onClick={() => select(entry)}
                  onKeyDown={(event) => keyboard(event, index)}
                >
                  <span aria-hidden="true">{level === 0 ? "·" : level < 3 ? "•" : "+"}</span>
                </button>
              );
            })}
          </div>
        ))}
      </div>
      <details className="mrg-heatmap__fallback">
        <summary>View values as a table</summary>
        <table>
          <caption>{label} data</caption>
          <thead>
            <tr>
              <th scope="col">Date</th>
              <th scope="col">Value</th>
            </tr>
          </thead>
          <tbody>
            {entries.map((entry) => (
              <tr key={entry.date}>
                <th scope="row">{formatter.format(validDate(entry.date))}</th>
                <td>{entry.value}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </details>
      {showSummary ? (
        <output
          aria-live="polite"
          className="mrg-heatmap__summary"
          data-slot="calendar-heatmap-summary"
        >
          {entries.length} days · {total} total ·{" "}
          {current === null ? "no date selected" : `${current} selected`}
        </output>
      ) : null}
    </section>
  );
}
